class Computation:
    def __init__(self):
        pass

    def Factorial(self, n):
        if n < 0:
            return "Factorial is not defined for negative integers."
        elif n == 0:
            return 1
        else:
            factorial = 1
            for i in range(1, n + 1):
                factorial = factorial * i
            return factorial

    def Sum(self, n):
        if n < 0:
            return "Sum is not defined for negative integers."
        else:
            return sum(range(1, n + 1))

